function LoadData(){$.ajax({url:"data/mydata.json",dataType:"text",success:function(e){InitTree($.parseJSON(e))}}).fail(function(){console.log("An error has occurred.")})}function InitTree(e){(oTree=$("#mytree").jstree({core:{multiple:!1,animation:200,themes:{theme:"default-dark",stripes:!1},data:e},plugins:["search"],search:{case_sensitive:!1,show_only_matches:!1}})).on("dblclick.jstree",function(e,a){var t=$("#mytree").jstree(!0).get_node(e.target);if(t.state.disabled,t.data&&(t.data.length>0||"object"==$.type(t.data))){if("object"==$.type(t.data))var r=t.data.file;else var r=t.data;if("http://"==r.substr(0,7)||"https://"==r.substr(0,8))return window.open(r),null;switch(cExt=r.substr(r.lastIndexOf(".")+1)){case"html":case"htm":case"pdf":LoadFrame(r,"data/")}}else $("#mybody").html("")}),oTree.on("ready.jstree",function(e,a){let t=window.location.search,r=new URLSearchParams(t),s=r.get("search");"string"==typeof s&&(console.log("Search -> ",s),TreeSearch(s))})}function LoadFrame(e,a){var t='<iframe class="myiframe" src="'+(a="string"==typeof a?a:"")+e+'" ></iframe>';$("#mybody").addClass("es_pdf"),$("#mybody").html(t)}function TreeSearch(e){if("string"==typeof e)var a=e;else var a=$("#tree_search").val();$("#mytree").jstree(!0).search(a)}$(document).ready(function(){console.log("Ready..."),LoadData(),$("#tree_search").change(TreeSearch)});